12:function record(root: string, label: string, event: string): string {
13:  mkdirSync(root, { recursive: true });
14:  const path = join(root, `${label}.events.jsonl`);
15:  appendFileSync(path, `${JSON.stringify({ event, timestamp: Date.now() })}\n`);
16:  return path;
17:}
