19:const nestedPromptChild = workflow({
20:  name: "workflow-resume-e2e-nested-child",
21:  description: "Nested child used only by the workflow-resume E2E fixture.",
22:  inputs: {
23:    marker_root: Type.String(),
24:    label: Type.String(),
25:  },
26:  outputs: fixtureOutputs,
27:  run: async (ctx) => {
28:    await ctx.tool("nested-before-prompt", { label: ctx.inputs.label }, async () =>
29:      record(ctx.inputs.marker_root, ctx.inputs.label, "nested-before-prompt"));
30:    const answer = await ctx.ui.input(`E2E nested answer for ${ctx.inputs.label}`);
31:    await ctx.tool("nested-after-prompt", { answer, label: ctx.inputs.label }, async () =>
32:      record(ctx.inputs.marker_root, ctx.inputs.label, `nested-after:${answer}`));
33:    return { result: `nested:${answer}`, status: "completed" as const, answers: [answer] };
34:  },
