37:export default workflow({
38:  name: "workflow-resume-e2e-fixture",
39:  description: "Durable checkpoint, prompt, failure, completion, and nested-child fixture for real /workflow resume QA.",
40:  inputs: {
41:    mode: Type.Union([
42:      Type.Literal("prompt"),
43:      Type.Literal("double-prompt"),
44:      Type.Literal("fail-once"),
45:      Type.Literal("completed"),
46:      Type.Literal("nested"),
47:    ]),
48:    marker_root: Type.String(),
49:    label: Type.String(),
50:  },
51:  outputs: fixtureOutputs,
52:  run: async (ctx) => {
53:    const { label, marker_root: markerRoot, mode } = ctx.inputs;
54:    const answers: string[] = [];
55:
56:    await ctx.tool("checkpoint-before", { label, mode }, async () =>
57:      record(markerRoot, label, "checkpoint-before"));
58:
59:    if (mode === "completed") {
60:      await ctx.tool("checkpoint-completed", { label }, async () =>
61:        record(markerRoot, label, "checkpoint-completed"));
62:      await ctx.stage("completed-proof").complete(`completed:${label}`);
63:      return { result: `completed:${label}`, status: "completed" as const, answers };
64:    }
65:
66:    if (mode === "fail-once") {
67:      const sentinel = join(markerRoot, `${label}.fail-once-sentinel`);
68:      await ctx.tool("fail-exactly-once", { label }, async () => {
69:        mkdirSync(markerRoot, { recursive: true });
70:        if (!existsSync(sentinel)) {
71:          writeFileSync(sentinel, "first-attempt-failed\n");
72:          record(markerRoot, label, "intentional-first-failure");
73:          throw new Error(`E2E intentional recoverable failure: ${label}`);
74:        }
75:        return record(markerRoot, label, "recovered-after-failure");
76:      });
77:      await ctx.stage("recoverable-proof").complete(`recovered:${label}`);
78:    } else if (mode === "nested") {
79:      const child = await ctx.workflow(nestedPromptChild, {
80:        stageName: "nested-resume-prompt",
81:        inputs: { marker_root: markerRoot, label },
82:      });
83:      answers.push(...child.outputs.answers);
84:    } else {
85:      const first = await ctx.ui.input(`E2E first answer for ${label}`);
86:      answers.push(first);
87:      await ctx.tool("checkpoint-after-first-answer", { first, label }, async () =>
88:        record(markerRoot, label, `first-answer:${first}`));
89:      if (mode === "double-prompt") {
90:        const second = await ctx.ui.input(`E2E second answer for ${label}`);
91:        answers.push(second);
92:        await ctx.tool("checkpoint-after-second-answer", { label, second }, async () =>
93:          record(markerRoot, label, `second-answer:${second}`));
94:      }
95:    }
96:
97:    await ctx.tool("checkpoint-final", { answers, label, mode }, async () =>
98:      record(markerRoot, label, `final:${answers.join("|")}`));
99:    return { result: `${mode}:${label}:${answers.join("|")}`, status: "completed" as const, answers };
100:  },
101:});
